package clickup

import (
	"fmt"
	"strings"
)

// MultipleWorkspacesError is returned when the ClickUp MCP detects multiple
// workspaces and no workspace_id was provided.
type MultipleWorkspacesError struct {
	WorkspaceIDs   []string
	WorkspaceNames map[string]string // id → name, populated by FetchWorkspaceNames
}

func (e *MultipleWorkspacesError) Error() string {
	return fmt.Sprintf("multiple clickup workspaces available: %s", strings.Join(e.WorkspaceIDs, ", "))
}

// MCPServerConfig holds the detected ClickUp MCP server configuration.
type MCPServerConfig struct {

package clickup

import (
	"encoding/json"
	"os"
	"path/filepath"
)

const projectConfigPath = ".kasmos/clickup.json"

// ProjectConfig holds per-project ClickUp settings persisted to .kasmos/clickup.json.
type ProjectConfig struct {
	WorkspaceID string `json:"workspace_id,omitempty"`
}

// LoadProjectConfig reads the ClickUp project config from <repoRoot>/.kasmos/clickup.json.
// Returns an empty config if the file doesn't exist or is corrupt.
func LoadProjectConfig(repoRoot string) *ProjectConfig {
	data, err := os.ReadFile(filepath.Join(repoRoot, projectConfigPath))
	if err != nil {

package clickup

import (
	"encoding/json"
	"fmt"
	"regexp"
	"strings"

	"github.com/kastheco/kasmos/internal/mcpclient"
)

// MCPCaller is the subset of mcpclient.Client that Importer needs.
type MCPCaller interface {
	CallTool(name string, args map[string]interface{}) (*mcpclient.ToolResult, error)
	FindTool(substring string) (mcpclient.Tool, bool)
}

// Importer searches and fetches ClickUp tasks via MCP.
type Importer struct {
	client      MCPCaller

package app

import (
	"github.com/kastheco/kasmos/config/planparser"
)

// WaveState represents the current state of wave orchestration for a plan.
type WaveState int

const (
	WaveStateIdle         WaveState = iota // Not started
	WaveStateRunning                       // Current wave's tasks are running
	WaveStateWaveComplete                  // Current wave finished, awaiting user confirmation
